<?php use yii\bootstrap5\ActiveForm; use yii\bootstrap5\Html; ?>
<div class="sz-panel"><?php $f=ActiveForm::begin(); echo $f->field($model,'title'); echo $f->field($model,'description')->textarea(); echo $f->field($model,'submit_label'); echo $f->field($model,'success_message')->textarea(); if (\larikmc\forms\models\Form::hasNotificationEmailsColumn()) { echo $f->field($model,'notification_emails')->textarea(['rows' => 3])->hint('Если оставить пустым, форма будет отправлять уведомления на e-mail по умолчанию из раздела "Настройки". Можно указать несколько адресов через запятую.'); } echo $f->field($model,'is_active')->checkbox(); echo Html::submitButton('Сохранить',['class'=>'btn btn-primary']); ActiveForm::end(); ?></div>
